import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Legacy Branch Overview","description":"","frontmatter":{"title":"Legacy Branch Overview","slug":"branch-dashboard-overview"},"headers":[],"relativePath":"marketer-hub/branch-dashboard-overview.md","filePath":"marketer-hub/branch-dashboard-overview.md"}'),n={name:"marketer-hub/branch-dashboard-overview.md"};function i(s,e,l,c,h,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Branch is rolling out a new interface! Your environment may contain new and legacy pages, depending on when you started using Branch.</p><p>For documentation on the new Branch experience, please visit our <a href="https://help.branch.io/docs/new-branch-overview" target="_blank" rel="noreferrer">New Branch Overview</a> article.</p></div><div class="info custom-block"><p class="custom-block-title">Note</p><p>We’ve updated the Branch Dashboard structure. For more information, please read the <a href="./new-navigation-structure.html">Branch Dashboard Navigation Update</a> changelog entry.</p></div><p>The Branch Dashboard is the primary location where you will work with Branch’s products and analytics. Any individual who has a Branch account can access the Branch Dashboard.</p><p>The three primary functions of the Dashboard include:</p><ul><li>Link and campaign creation</li><li>Metrics and insights analysis</li><li>Account settings configuration</li></ul><h2 id="analysis-section" tabindex="-1">Analysis section <a class="header-anchor" href="#analysis-section" aria-label="Permalink to &quot;Analysis section&quot;">​</a></h2><p>View metrics for for campaigns, fraud, ads, and more.</p><h3 id="overview-page" tabindex="-1">Overview page <a class="header-anchor" href="#overview-page" aria-label="Permalink to &quot;Overview page&quot;">​</a></h3><p>The first page you will see when logging into the Branch Dashboard is the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Overview</a> page. This dashboard provides a global overview of your Branch analytics across all your channels, campaigns, and use cases for Branch linking.</p><p>Shortcuts allow quick access to view data for:</p><ul><li>All Data</li><li>Journeys</li><li>Short Links</li><li>Ads</li><li>Email</li></ul><p>The Overview page allows you to:</p><ul><li>View data custom date ranges and data granularity</li><li>Select the metrics you would like to view and how you would like to compare them, both visually and in Table form.</li><li>Share reports with other stakeholders on your team</li></ul><p><strong>Date Ranges</strong></p><p>Choose a pre-set date range via the drop-down menu or customize the time frame using the date selector.</p><p><strong>Sharing and Saving</strong></p><p>Create a Branch Link to share your view with another person on your team or save your report to come back to at another time.</p><p><strong>Summary Tiles</strong></p><p>Summary tiles are customizable and allow for the selection of the metrics that are the most important to you.</p><p><strong>Summary Graph</strong></p><p>Select the metrics (downloads, clicks, installs etc.) and how you would like to compare them (ad partner, campaign, device type, geography etc.) In order to explore a visual breakdown of the data. View more closely or export the graphs for later use.</p><p><strong>Events/ Performance Table</strong></p><p>View a table breakdown for the time window selected at the top of the page. Again, select the metrics you would like to view and how you would like to compare them, this time, via the &quot;add columns&quot; button, &quot;Compare By&quot; dropdown, and additional filters. Download the data to CSV for additional analysis.</p><p>For in-depth information about the Overview page, read our <a href="./branch-summary-page.html">Overview Page</a> article.</p><p>For additional information about Sharing and Dashboard reporting, read our <a href="./dashboard-reports.html#eventsperformance-table">Dashboard Reports</a> article.</p><h3 id="ads-analytics-page" tabindex="-1">Ads Analytics page <a class="header-anchor" href="#ads-analytics-page" aria-label="Permalink to &quot;Ads Analytics page&quot;">​</a></h3><p>Set up your Ad Partner connections and Postbacks, create tracking links for new campaigns, analyze potential fraud, and view your analytics for both traditional campaigns and SKAdNetwork campaigns.</p><p><strong>Analytics</strong></p><p>View Analytics specifically for your Ads Channel. Similar to the Branch Overview Page, Select your Time Range, Metrics, and Compare Bys and see your data both visually and in data table form.</p><p><strong>SKAdNetwork</strong></p><p>Configure SKAdNetwork with Branch and view SKAdNetwork-specific conversion data. Learn more about SKAdNetwork <a href="./skadnetwork.html">here</a></p><p>For more information about Ads, take a look at our <a href="./ads-overview.html">Ads Overview Guide</a> as well as our <a href="./universal-ad-partner-integration-guide.html">Partner Integration Guide</a> and our <a href="./ad-links.html">Creating Ad Links Guide</a>.</p><h3 id="fraud-page" tabindex="-1"><strong>Fraud page</strong> <a class="header-anchor" href="#fraud-page" aria-label="Permalink to &quot;**Fraud page**&quot;">​</a></h3><p>Generate reports to see which clicks and conversions have been blocked by Branch&#39;s anomaly detection practices. Learn more about Branch&#39;s fraud solution <a href="./fraud.html">here</a>.</p><h2 id="campaigns-section" tabindex="-1">Campaigns section <a class="header-anchor" href="#campaigns-section" aria-label="Permalink to &quot;Campaigns section&quot;">​</a></h2><h3 id="linkhub-page" tabindex="-1">LinkHub page <a class="header-anchor" href="#linkhub-page" aria-label="Permalink to &quot;LinkHub page&quot;">​</a></h3><p>Create and manage links and QR codes that can be used in every channel online and off.</p><h3 id="journeys-page" tabindex="-1">Journeys page <a class="header-anchor" href="#journeys-page" aria-label="Permalink to &quot;Journeys page&quot;">​</a></h3><p>Design completely custom banners and interstitials for your mobile website. Target audiences, run A/B tests, and view Journeys-specific analytics including Pageviews, Journeys Impressions, View-to-Click ratios etc.</p><p>For more information about Journeys, Take a look at our <a href="./journeys-overview.html">Journeys Overview Guide</a>.</p><h3 id="email-page" tabindex="-1">Email page <a class="header-anchor" href="#email-page" aria-label="Permalink to &quot;Email page&quot;">​</a></h3><p>Enable your Email Service Provider&#39;s integration with Branch to allow you to deep link from your emails to your app within your current email marketing setup flow. View your email-specific analytics including clicks and in-app conversions from your email campaigns.</p><p>For more information about Branch’s Email feature, take a look at our <a href="./branch-universal-email.html">Overview Guide</a> as well as our <a href="./universal-email-integration-guide.html">Integration Guide</a>.</p><h3 id="engagement-builder-page" tabindex="-1"><strong>Engagement Builder page</strong> <a class="header-anchor" href="#engagement-builder-page" aria-label="Permalink to &quot;**Engagement Builder page**&quot;">​</a></h3><p>Create rules to help you identify groups of users to target in re-engagement campaigns and share these groups of users directly with your ad networks.</p><h2 id="configure-section" tabindex="-1">Configure section <a class="header-anchor" href="#configure-section" aria-label="Permalink to &quot;Configure section&quot;">​</a></h2><h3 id="app-settings" tabindex="-1"><strong>App Settings</strong> <a class="header-anchor" href="#app-settings" aria-label="Permalink to &quot;**App Settings**&quot;">​</a></h3><p>Tell Branch exactly how to act when one of your Branch Links is clicked, create your custom domain, and more. For more information, visit our Configuration Guide <a href="./configure-default-link-behaviors.html">here</a></p><p><strong>Integration Status</strong></p><p>View the status of your Branch Integration progress. See the additional steps that need to be completed, and link to relevant integration documentation.</p><p><strong>Test Devices</strong></p><p>Set up test devices to ensure that conversions resulting from your testing do not appear in your regular traffic and re-set devices to allow you to test installs more than once. See our Test Device Guide <a href="./add-test-devices.html">here</a>.</p><h3 id="ad-partners-page" tabindex="-1"><strong>Ad Partners page</strong> <a class="header-anchor" href="#ad-partners-page" aria-label="Permalink to &quot;**Ad Partners page**&quot;">​</a></h3><p>Set up your connections to Ad Partners including Self-Attributing and Traditional Networks. Create, edit, and test postbacks to Branch from your networks.</p><h3 id="roi-hub" tabindex="-1">ROI Hub <a class="header-anchor" href="#roi-hub" aria-label="Permalink to &quot;ROI Hub&quot;">​</a></h3><p>ROI Hub is a critical tool in your marketing strategy if you&#39;re interested in analyzing and reporting on ad spend to make sure you&#39;re getting the best use of your investment dollars. ROI Hub unifies your cost data and revenue insights, and helps you understand the actual impact of your ad dollars.</p><h3 id="data-feeds" tabindex="-1"><strong>Data Feeds</strong> <a class="header-anchor" href="#data-feeds" aria-label="Permalink to &quot;**Data Feeds**&quot;">​</a></h3><p>Enable Branch&#39;s <a href="./daily-exports-api.html">Daily Export API</a> to send Branch Data to an S3 bucket for retrieval by your team, and set up automatic data sending via pre-built integrations with Branch&#39;s marketing analytics partners.</p><h3 id="exports" tabindex="-1">Exports <a class="header-anchor" href="#exports" aria-label="Permalink to &quot;Exports&quot;">​</a></h3><p><strong>Daily Exports</strong></p><p>Retrieve daily exports from Branch&#39;s Dashboard interface.</p><p><strong>Custom Exports</strong></p><p>Generate a completely custom data export with the topics, events, and columns of your choosing via the Branch user interface</p><h2 id="account-section" tabindex="-1"><strong>Account section</strong> <a class="header-anchor" href="#account-section" aria-label="Permalink to &quot;**Account section**&quot;">​</a></h2><h3 id="settings-page" tabindex="-1"><strong>Settings page</strong> <a class="header-anchor" href="#settings-page" aria-label="Permalink to &quot;**Settings page**&quot;">​</a></h3><p>Retrieve your Branch key and secret and control permissions for team member and agency access to your Branch Data and configurations. More on users and permissions <a href="./entity-views-access-controls-overview.html">here</a></p>',66)])])}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
